sql:
SELECT MAX(date) AS most_recent_news_date
FROM news_feed
WHERE stock_id = 0;

SELECT title
FROM news_feed
WHERE stock_id = 0;

SELECT sector_name
FROM sectors
ORDER BY sector_name;

